class Solution:
    def getHint(self, secret: str, guess: str) -> str:
        bulls = 0
        cnt_s = [0] * 10
        cnt_g = [0] * 10
        for a, b in zip(secret, guess):
            if a == b:
                bulls += 1
            else:
                cnt_s[int(a)] += 1
                cnt_g[int(b)] += 1
        cows = sum(min(cnt_s[i], cnt_g[i]) for i in range(10))
        return f"{bulls}A{cows}B"

